function Sync-ADUsersFromCSV {
    param(
        [Parameter(Mandatory)][string]$CSVPath,
        [switch]$WhatIf
    )

    $Users   = Import-Csv -Path $CSVPath -Encoding UTF8
    $Results = foreach ($Row in $Users) {
        try {
            $Params = @{
                Identity    = $Row.SamAccountName
                Title       = $Row.Title
                Department  = $Row.Department
                OfficePhone = $Row.PhoneNumber
            }
            if ($Row.Manager) {
                $Params.Manager = (Get-ADUser $Row.Manager).DistinguishedName
            }
            if (-not $WhatIf) { Set-ADUser @Params }
            [PSCustomObject]@{ User=$Row.SamAccountName; Status="OK" }
        } catch {
            [PSCustomObject]@{ User=$Row.SamAccountName; Status="ERREUR"; Detail=$_.Exception.Message }
        }
    }

    $Results | Format-Table -AutoSize
    Write-Host "OK:$(($Results|Where-Object Status -eq 'OK').Count)  Erreurs:$(($Results|Where-Object Status -eq 'ERREUR').Count)"
}

function Get-ADExpiredAccounts {
    param(
        [int]$ExpirantDans = 30,
        [string]$Output    = "C:\\Logs\\ComptesExpires_$(Get-Date -f yyyyMMdd).csv"
    )

    $Now    = Get-Date
    $Limite = $Now.AddDays($ExpirantDans)

    $Comptes = Get-ADUser -Filter { Enabled -eq $true } `
        -Properties AccountExpirationDate, Department, EmailAddress |
    Where-Object {
        $_.AccountExpirationDate -and $_.AccountExpirationDate -lt $Limite
    }

    $Rapport = $Comptes | ForEach-Object {
        [PSCustomObject]@{
            Login         = $_.SamAccountName
            Nom           = $_.Name
            Email         = $_.EmailAddress
            Departement   = $_.Department
            Expiration    = $_.AccountExpirationDate
            Statut        = if ($_.AccountExpirationDate -lt $Now) { "EXPIRE" } else { "EXPIRE BIENTOT" }
            JoursRestants = [math]::Round(($_.AccountExpirationDate - $Now).TotalDays)
        }
    } | Sort-Object JoursRestants

    $Rapport | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Warning "$($Rapport.Count) compte(s) expires ou expirant dans $ExpirantDans jours."
    $Rapport | Format-Table Login, Statut, JoursRestants -AutoSize
}

