function Invoke-IntuneDeviceWipe {
    param(
        [Parameter(Mandatory)][string]$DeviceName,
        [switch]$KeepUserData,
        [switch]$Force
    )

    $Device = Get-MgDeviceManagementManagedDevice `
        -Filter "deviceName eq '$DeviceName'" | Select-Object -First 1

    if (-not $Device) { Write-Error "Appareil '$DeviceName' introuvable."; return }

    Write-Host "ATTENTION : Operation irreversible sur $DeviceName" -ForegroundColor Red
    Write-Host "Utilisateur : $($Device.UserPrincipalName)"

    if (-not $Force) {
        $Confirm = Read-Host "Taper OUI pour confirmer"
        if ($Confirm -ne "OUI") { Write-Host "Annule."; return }
    }

    try {
        if ($KeepUserData) {
            Invoke-MgRetireDeviceManagementManagedDevice -ManagedDeviceId $Device.Id
            Write-Host "Retire : $DeviceName" -ForegroundColor Yellow
        } else {
            Invoke-MgWipeDeviceManagementManagedDevice -ManagedDeviceId $Device.Id
            Write-Host "Wipe complet lance : $DeviceName" -ForegroundColor Red
        }
    } catch {
        Write-Error "Erreur wipe : $_"
    }
}

