    param(
        [string]$Output = "C:\\Logs\\ConfigProfiles_$(Get-Date -f yyyyMMdd).csv"
    )

    $Profiles = Get-MgDeviceManagementDeviceConfiguration -All

    $Rapport = $Profiles | ForEach-Object {
        $Assignments = Get-MgDeviceManagementDeviceConfigurationAssignment `
            -DeviceConfigurationId $_.Id -ErrorAction SilentlyContinue

        [PSCustomObject]@{
            Nom           = $_.DisplayName
            Plateforme    = $_.AdditionalProperties["@odata.type"] -replace "#microsoft.graph.",""
            Description   = $_.Description
            NbAssignments = $Assignments.Count
            CreeLe        = $_.CreatedDateTime
            ModifieLe     = $_.LastModifiedDateTime
            Id            = $_.Id
        }
    }

    $Rapport | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Host "$($Rapport.Count) profils exportes vers $Output"
    $Rapport | Format-Table Nom, Plateforme, NbAssignments -AutoSize
}

function Add-IntunePolicyAssignment {
    param(
        [Parameter(Mandatory)][string]$PolicyId,
        [Parameter(Mandatory)][string]$GroupId,
        [string]$PolicyType = "compliancePolicy"
    )

    $Assignment = @{
        target = @{
            "@odata.type" = "#microsoft.graph.groupAssignmentTarget"
            groupId       = $GroupId
        }
    }

    try {
        switch ($PolicyType) {
            "compliancePolicy" {
                New-MgDeviceManagementDeviceCompliancePolicyAssignment `
                    -DeviceCompliancePolicyId $PolicyId `
                    -BodyParameter $Assignment
            }
            "configurationPolicy" {
                New-MgDeviceManagementDeviceConfigurationAssignment `
                    -DeviceConfigurationId $PolicyId `
                    -BodyParameter $Assignment
            }
        }
        Write-Host "Policy $PolicyId assignee au groupe $GroupId." -ForegroundColor Green
    } catch {
        Write-Error "Erreur assignation : $_"
    }
}

function New-IntuneRemediationScript {
    param(
        [Parameter(Mandatory)][string]$Nom,
        [Parameter(Mandatory)][string]$DetectionScriptPath,
        [Parameter(Mandatory)][string]$RemediationScriptPath,
        [string]$Publisher = "IT Admin",
        [string]$RunAs     = "system"
    )

    $DetB64 = [Convert]::ToBase64String(
        [System.Text.Encoding]::UTF8.GetBytes((Get-Content $DetectionScriptPath -Raw))
    )
    $RemB64 = [Convert]::ToBase64String(
        [System.Text.Encoding]::UTF8.GetBytes((Get-Content $RemediationScriptPath -Raw))
    )

    $Body = @{
        displayName              = $Nom
        publisher                = $Publisher
        runAs32Bit               = $false
        runAsAccount             = $RunAs
        detectionScriptContent   = $DetB64
        remediationScriptContent = $RemB64
        enforceSignatureCheck    = $false
    } | ConvertTo-Json

    try {
        $R = Invoke-MgGraphRequest -Method POST `
            -Uri "deviceManagement/deviceHealthScripts" `
            -Body $Body `
            -ContentType "application/json"
        Write-Host "Script '$Nom' cree : $($R.id)" -ForegroundColor Green
        return $R
    } catch {
        Write-Error "Erreur : $_"
    }
}

function Get-IntuneInstalledAppsReport {
    param(
        [Parameter(Mandatory)][string]$DeviceName,
        [string]$Output = "C:\\Logs\\Apps_$(Get-Date -f yyyyMMdd).csv"
    )

    $Device = Get-MgDeviceManagementManagedDevice `
        -Filter "deviceName eq '$DeviceName'" | Select-Object -First 1

    if (-not $Device) { Write-Error "Appareil '$DeviceName' introuvable."; return }

    $Apps = Get-MgDeviceManagementManagedDeviceDetectedApp `
        -ManagedDeviceId $Device.Id -All

    $Rapport = $Apps | ForEach-Object {
        [PSCustomObject]@{
            Application = $_.DisplayName
            Version     = $_.Version
            TailleOctets= $_.SizeInByte
            Editeur     = $_.Publisher
        }
    } | Sort-Object Application

    $Rapport | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    Write-Host "$($Rapport.Count) applications trouvees sur $DeviceName."
}

function Import-AutopilotDevices {
    param(
        [Parameter(Mandatory)][string]$CSVPath
        # CSV : Device Serial Number, Windows Product ID, Hardware Hash
    )

    $Devices = Import-Csv -Path $CSVPath

    $Results = foreach ($D in $Devices) {
        $Body = @{
            "@odata.type"      = "#microsoft.graph.importedWindowsAutopilotDeviceIdentity"
            serialNumber       = $D."Device Serial Number"
            productKey         = $D."Windows Product ID"
            hardwareIdentifier = $D."Hardware Hash"
        } | ConvertTo-Json

        try {
            $R = Invoke-MgGraphRequest -Method POST `
                -Uri "deviceManagement/importedWindowsAutopilotDeviceIdentities" `
                -Body $Body -ContentType "application/json"
            [PSCustomObject]@{ Serial=$D."Device Serial Number"; Status="Importe"; Id=$R.id }
        } catch {
            [PSCustomObject]@{ Serial=$D."Device Serial Number"; Status="ERREUR"; Detail=$_.Exception.Message }
        }
    }

    $Results | Format-Table -AutoSize
    Write-Host "Importes : $(($Results|Where-Object Status -eq 'Importe').Count) / $($Results.Count)"
}

function Get-IntuneComplianceSummaryByOS {
    param(
        [string]$Output = "C:\\Logs\\ComplianceSummary_$(Get-Date -f yyyyMMdd).csv"
    )

    $Devices = Get-MgDeviceManagementManagedDevice -All

    $Summary = $Devices |
        Group-Object OperatingSystem |
        ForEach-Object {
            $G   = $_.Group
            $Tot = $G.Count
            $OK  = ($G | Where-Object ComplianceState -eq "compliant").Count
            $Pct = if ($Tot -gt 0) { [math]::Round($OK/$Tot*100,1) } else { 0 }

            [PSCustomObject]@{
                OS             = $_.Name
                TotalAppareils = $Tot
                Conformes      = $OK
                NonConformes   = $Tot - $OK
                TauxConformite = "$Pct%"
            }
        } | Sort-Object TotalAppareils -Descending

    $Summary | Export-Csv -Path $Output -NoTypeInformation -Encoding UTF8
    $Summary | Format-Table -AutoSize
    Write-Host "Rapport genere : $Output"
}
